const stdout = $input.first().json.stdout || '';

let testFiles = [];
try {
  const parsed = JSON.parse(stdout.trim());
  if (Array.isArray(parsed)) {
    testFiles = parsed;
  } else if (typeof parsed === 'string' && parsed.endsWith('.cy.js')) {
    testFiles = [parsed];
  }
} catch(e) {
  testFiles = stdout.trim().split('\n').map(l => l.trim()).filter(l => l.endsWith('.cy.js'));
}

const now = new Date();
const pad = n => String(n).padStart(2,'0');
const runId = 'run-' + now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());

return [{
  json: {
    runId,
    startTime: now.toISOString(),
    startTimeFormatted: now.toLocaleString('fa-IR', { timeZone: 'Asia/Tehran' }),
    totalTests: testFiles.length,
    testFiles,
    baseUrl: 'https://app.aihomedesign.com'
  }
}];

