const stdout = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;

const endTime = new Date();
const prevData = $('Set Run Config & Metadata').first().json;
const startTime = new Date(prevData.startTime);
const durationMs = endTime - startTime;
const durationMin = Math.floor(durationMs / 60000);
const durationSec = Math.floor((durationMs % 60000) / 1000);

let passed = 0, failed = 0, pending = 0, skipped = 0;
let failedTests = [];
let passedTests = [];
let suiteResults = [];
let parsedOk = false;

const resultsFile = 'C:\\Users\\me.moslemi\\Desktop\\cypress-e2e\\cypress-results.json';
let parsed = null;
try {
  const fs = require('fs');
  if (fs.existsSync(resultsFile)) {
    const raw = fs.readFileSync(resultsFile, 'utf8');
    parsed = JSON.parse(raw);
    if (parsed.stats) {
      parsedOk = true;
      passed  = parsed.stats.passes   || (parsed.passes ? parsed.passes.length : 0);
      failed  = parsed.stats.failures || (parsed.failures ? parsed.failures.length : 0);
      pending = parsed.stats.pending  || (parsed.pending ? parsed.pending.length : 0);
      skipped = parsed.stats.skipped  || (parsed.skipped ? parsed.skipped.length : 0);
      for (const t of (parsed.passes || [])) {
        passedTests.push({ suite: (t.fullTitle||'').split(' ')[0], title: t.fullTitle || t.title });
      }
      for (const t of (parsed.failures || [])) {
        const errMsg = t.err ? (t.err.message || '') : 'Unknown error';
        const firstLine = errMsg.split('\n')[0].replace(/^CypressError:\s*/, '').substring(0, 200);
        failedTests.push({ suite: (t.fullTitle||'').split(' ')[0], title: t.fullTitle || t.title || 'Unknown', error: firstLine });
      }
      const suiteMap = {};
      for (const t of (parsed.tests || [])) {
        const sName = (t.fullTitle || '').split(' ')[0] || 'Unknown';
        if (!suiteMap[sName]) suiteMap[sName] = { name: sName, passed: 0, failed: 0, tests: [] };
        const hasFailed = t.err && t.err.message && t.err.message.length > 0;
        const status = hasFailed ? 'FAIL' : 'PASS';
        if (hasFailed) suiteMap[sName].failed++; else suiteMap[sName].passed++;
        const errFirst = hasFailed ? t.err.message.split('\n')[0].replace(/^CypressError:\s*/, '').substring(0, 150) : '';
        suiteMap[sName].tests.push({ name: t.fullTitle || t.title, status, error: errFirst });
      }
      suiteResults = Object.values(suiteMap).map(s => ({ ...s, total: s.passed + s.failed, status: s.failed > 0 ? 'FAIL' : 'PASS' }));
    }
  }
} catch(e) {}

if (!parsedOk) {
  const passM = stdout.match(/(\d+) passing/);
  const failM = stdout.match(/(\d+) failing/);
  if (passM) passed = parseInt(passM[1]);
  if (failM) failed = parseInt(failM[1]);
}

// Fallback: اگر از stats و آرایه‌های top-level تست نگرفتیم، از ساختار results استفاده کن
if (passed === 0 && failed === 0 && parsed && parsed.results && Array.isArray(parsed.results)) {
  for (const r of parsed.results) {
    const suites = r.suites || [];
    for (const suite of suites) {
      const tests = suite.tests || [];
      for (const t of tests) {
        const hasFailed = !!(t.err && t.err.message);
        const title = t.fullTitle || t.title;
        const errFirst = hasFailed ? (t.err.message || '').split('
')[0].substring(0, 200) : '';
        if (hasFailed) {
          failed++;
          failedTests.push({ title, error: errFirst });
        } else {
          passed++;
          passedTests.push({ title });
        }
      }
    }
    for (const t of tests) {
      const hasFailed = !!(t.err && t.err.message);
      const title = t.fullTitle || t.title;
      const errFirst = hasFailed ? t.err.message.split('\n')[0].substring(0, 200) : '';
      if (hasFailed) {
        failed++;
        failedTests.push({ title, error: errFirst });
      } else {
        passed++;
        passedTests.push({ title });
      }
    }
  }
}

const total = passed + failed + pending + skipped;
const successRate = total > 0 ? Math.round((passed / total) * 100) : 0;
const overallStatus = total === 0 ? 'NO_TESTS' : (failed === 0 ? 'PASS' : 'FAIL');

return [{
  json: {
    runId: prevData.runId,
    overallStatus,
    successRate,
    stats: { passed, failed, pending, skipped, total },
    failedTests,
    passedTests,
    suiteResults,
    duration: durationMin + 'm ' + durationSec + 's',
    endTimeFormatted: endTime.toLocaleString('fa-IR', { timeZone: 'Asia/Tehran' }),
    startTimeFormatted: prevData.startTimeFormatted,
    baseUrl: prevData.baseUrl,
    hasErrors: failed > 0,
    exitCode,
    parsedOk
  }
}];

const d = $input.first().json;

let lines = [];
lines.push(':red_circle: *Cypress Test Report — FAILED*');
lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('*Run ID:* `' + d.runId + '`');
lines.push('*Result:* FAIL  |  *Duration:* ' + d.duration);


lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('*Test Details:*');

let hasAny = false;

if (d.suiteResults && d.suiteResults.length > 0) {
  for (const s of d.suiteResults) {
    const si = s.status === 'PASS' ? ':white_check_mark:' : ':x:';
    lines.push(si + ' *' + s.name + '* (' + s.passed + ' passed, ' + s.failed + ' failed)');
    for (const t of (s.tests || [])) {
      hasAny = true;
      const ti = t.status === 'PASS' ? '  :white_check_mark:' : '  :x:';
      lines.push(ti + ' ' + t.name);
      if (t.status === 'FAIL' && t.error) {
        lines.push('    > `' + t.error.substring(0, 200) + '`');
      }
    }
  }
}

if ((!d.suiteResults || d.suiteResults.length === 0) && d.failedTests && d.failedTests.length > 0) {
  for (const t of d.failedTests) {
    hasAny = true;
    lines.push('  :x: ' + (t.title || t.fullTitle || 'Unknown test'));
    if (t.error) {
      lines.push('    > `' + t.error.substring(0, 200) + '`');
    }
  }
}

if ((!d.suiteResults || d.suiteResults.length === 0) && d.passedTests && d.passedTests.length > 0) {
  for (const t of d.passedTests) {
    hasAny = true;
    lines.push('  :white_check_mark: ' + (t.title || t.fullTitle || 'Unknown test'));
  }
}

if (!hasAny) {
  lines.push(':x: No test details available (parsedOk=' + d.parsedOk + ')');
}

lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('_' + d.startTimeFormatted + ' → ' + d.endTimeFormatted + '_');

return [{ json: { slackText: lines.join('\n'), ...d } }];

const d = $input.first().json;

let lines = [];
lines.push(':large_green_circle: *Cypress Test Report — ALL PASSED*');
lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('*Run ID:* `' + d.runId + '`');
lines.push('*Result:* PASS  |  *Duration:* ' + d.duration);


lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('*Test Details:*');

let hasAny = false;

if (d.suiteResults && d.suiteResults.length > 0) {
  for (const s of d.suiteResults) {
    lines.push(':white_check_mark: *' + s.name + '* (' + s.passed + ' passed)');
    for (const t of (s.tests || [])) {
      hasAny = true;
      lines.push('  :white_check_mark: ' + t.name);
    }
  }
}

if ((!d.suiteResults || d.suiteResults.length === 0) && d.passedTests && d.passedTests.length > 0) {
  for (const t of d.passedTests) {
    hasAny = true;
    lines.push('  :white_check_mark: ' + (t.title || t.fullTitle || 'Unknown test'));
  }
}

if (!hasAny) {
  lines.push(':white_check_mark: All tests passed (no per-test details)');
}

lines.push('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
lines.push('_' + d.startTimeFormatted + ' → ' + d.endTimeFormatted + '_');

return [{ json: { slackText: lines.join('\n'), ...d } }];

const slackResponse = $input.first().json;
const testData = $('Parse Test Results').first().json;
const stats = testData.stats || { passed: 0, failed: 0, total: 0 };
console.log('[CypressRunner] ' + testData.runId + ' | ' + testData.overallStatus + ' | passed:' + stats.passed + ' failed:' + stats.failed + ' | ' + testData.duration + ' | slack:' + (slackResponse.ok ? 'ok' : 'fail'));
return [{ json: { ...testData, slackDelivered: slackResponse.ok === true } }];
